window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["osha-construction"] = window.COURSE_LANG["osha-construction"] || {};
window.COURSE_LANG["osha-construction"]["es"] = [
  {"id":1,"q":"OSHA significa:","opts":["Administración de Seguridad y Salud Ocupacional","Oficina de Concientización sobre Seguridad y Peligros","Organización para el Manejo y Ensamblaje Seguros","Normas Ocupacionales para Equipo Pesado"],"re":"OSHA es la Occupational Safety and Health Administration (Administración de Seguridad y Salud Ocupacional), creada por la OSH Act de 1970."},
  {"id":2,"q":"Según la OSH Act, el deber principal del empleador es:","opts":["Dar comidas gratis","Pagar horas extra","Proporcionar un lugar de trabajo libre de peligros graves reconocidos","Dar uniformes de la empresa"],"re":"La Cláusula de Deber General exige al empleador un lugar de trabajo libre de peligros reconocidos que puedan causar muerte o daño grave."},
  {"id":3,"q":"¿Cuál de estos es un derecho del trabajador bajo OSHA?","opts":["Ignorar las reglas de seguridad","Saltarse la capacitación obligatoria","Quitar las guardas de las máquinas","Reportar un peligro sin temor a represalias"],"re":"Los trabajadores pueden reportar peligros o presentar quejas sin represalias y deben recibir capacitación que entiendan."},
  {"id":4,"q":"La capacitación exigida por OSHA debe darse:","opts":["Solo en inglés","En un idioma y vocabulario que el trabajador entienda","Solo a los supervisores","Una sola vez en la carrera"],"re":"OSHA exige capacitación en un idioma y vocabulario que los trabajadores puedan entender."},
  {"id":5,"q":"La tarjeta de OSHA para trabajadores de construcción de nivel inicial es la:","opts":["OSHA de 30 horas","OSHA de 10 horas","OSHA 500","OSHA 7600"],"re":"El curso OSHA de 10 horas (Construction) es para trabajadores de nivel inicial; el de 30 horas es para supervisores."},
  {"id":6,"q":"Las lesiones y enfermedades relacionadas con el trabajo se registran en el:","opts":["OSHA 100","OSHA 200","Registro OSHA 300","OSHA 1A"],"re":"Las lesiones y enfermedades registrables se anotan en el formulario OSHA 300."},
  {"id":7,"q":"Una muerte relacionada con el trabajo debe reportarse a OSHA dentro de:","opts":["8 horas","24 horas","48 horas","7 días"],"re":"Reporta una muerte dentro de 8 horas; una hospitalización, amputación o pérdida de un ojo dentro de 24 horas."},
  {"id":8,"q":"Una persona competente en la obra es alguien que:","opts":["Es dueño de la empresa","Ha trabajado al menos un año","Tiene cualquier licencia estatal","Puede identificar peligros y está autorizado a corregirlos"],"re":"Una persona competente identifica peligros existentes y previsibles y tiene autoridad para tomar medidas correctivas."},
  {"id":9,"q":"En construcción, la protección contra caídas suele exigirse a una altura de:","opts":["4 pies","6 pies","10 pies","20 pies"],"re":"En construcción la protección contra caídas se exige a 6 pies sobre un nivel inferior (industria general: 4 pies)."},
  {"id":10,"q":"Entre los Focus Four de OSHA, las caídas son:","opts":["No están incluidas","La principal causa de muertes en construcción","El peligro menos común","Un peligro solo en andamios"],"re":"Las caídas son la principal causa de muerte en construcción y el primero de los Focus Four."},
  {"id":11,"q":"Un sistema personal de detención de caídas (PFAS) consta de:","opts":["Solo un cinturón de cuerpo","Un casco y guantes","Un anclaje, un arnés de cuerpo completo y un conector","Una baranda sola"],"re":"Un PFAS tiene tres partes: anclaje, arnés de cuerpo completo y un conector como una eslinga o línea de vida."},
  {"id":12,"q":"Para detención de caídas, un cinturón de cuerpo (en vez de arnés de cuerpo completo) es:","opts":["Recomendado","Obligatorio","Lo más cómodo","No permitido"],"re":"Los cinturones de cuerpo están prohibidos para detención de caídas; debe usarse un arnés de cuerpo completo."},
  {"id":13,"q":"El riel superior de una baranda estándar está a qué altura sobre la superficie?","opts":["12 pulgadas","21 pulgadas","42 pulgadas","60 pulgadas"],"re":"El riel superior está a unas 42 pulgadas (más o menos 3), con un riel intermedio cerca de 21 pulgadas."},
  {"id":14,"q":"Una escalera recta o de extensión debe sobresalir por encima del descanso superior al menos:","opts":["3 pies","1 pie","6 pulgadas","No debe sobresalir"],"re":"Los largueros de la escalera deben sobresalir al menos 3 pies por encima del descanso."},
  {"id":15,"q":"La regla del ángulo seguro para una escalera recta es:","opts":["La regla 1:1","La regla 4:1 (1 pie de separación por cada 4 pies de altura)","La regla 10:1","No hay regla"],"re":"Coloca la base a 1 pie de separación por cada 4 pies de altura de trabajo — la regla 4:1."},
  {"id":16,"q":"En una escalera de tijera nunca debes:","opts":["Mirar hacia la escalera","Mantener tres puntos de contacto","Abrirla por completo antes de usarla","Pararte en la tapa o en los dos peldaños superiores"],"re":"Nunca te pares en la tapa superior ni en los dos peldaños más altos de una escalera de tijera."},
  {"id":17,"q":"Las plataformas de andamio con apoyo necesitan protección contra caídas cuando superan:","opts":["2 pies de altura","4 pies de altura","10 pies de altura","25 pies de altura"],"re":"Las plataformas de andamio a más de 10 pies sobre un nivel inferior requieren protección contra caídas."},
  {"id":18,"q":"Antes de dar servicio a un equipo, la energía peligrosa debe controlarse con:","opts":["Un descanso","Bloqueo/Etiquetado (Lockout/Tagout, LOTO)","Un casco","Una escalera más alta"],"re":"El Lockout/Tagout aísla y desenergiza el equipo para que no arranque durante el servicio."},
  {"id":19,"q":"En las obras, los tomacorrientes para herramientas deben protegerse con:","opts":["Protección GFCI (interruptor de falla a tierra)","Una regleta","Un cable más largo","Un temporizador"],"re":"Se exige protección GFCI (o un programa de conductor de puesta a tierra asegurada) en las obras."},
  {"id":20,"q":"Debes tratar toda línea eléctrica aérea como:","opts":["Desenergizada","Segura si se ve vieja","Solo una guía","Energizada y peligrosa"],"re":"Asume siempre que las líneas aéreas están energizadas y mantén la distancia requerida."},
  {"id":21,"q":"Para líneas aéreas de hasta 50 kV, mantén una distancia mínima de:","opts":["3 pies","10 pies","50 pies","No se necesita distancia"],"re":"Mantén al menos 10 pies de distancia de líneas de hasta 50 kV (más para voltajes mayores)."},
  {"id":22,"q":"¿Quién puede trabajar en o cerca de partes energizadas expuestas?","opts":["Cualquiera en la obra","Aprendices trabajando solos","Solo una persona calificada","El trabajador más nuevo"],"re":"Solo una persona calificada y capacitada en los peligros puede trabajar en o cerca de partes energizadas expuestas."},
  {"id":23,"q":"Un cable de extensión con aislamiento dañado y cables expuestos debe ser:","opts":["Envuelto en cinta y usado","Usado solo al aire libre","Usado solo para cargas ligeras","Retirado del servicio"],"re":"Retira del servicio los cables dañados; nunca uses un cable con aislamiento dañado o conductores expuestos."},
  {"id":24,"q":"La pata de tierra de un enchufe de tres patas debe:","opts":["Dejarse intacta para dar un camino seguro a tierra","Quitarse por comodidad","Doblarse a un lado","Pintarse"],"re":"Nunca quites la pata de tierra; provee un camino seguro para la corriente de falla."},
  {"id":25,"q":"La norma de OSHA que controla la energía peligrosa durante el servicio es:","opts":["Comunicación de Peligros","Protección contra Caídas","Bloqueo/Etiquetado (Lockout/Tagout)","Protección Respiratoria"],"re":"La norma de Control de Energía Peligrosa (Lockout/Tagout) evita un arranque inesperado."},
  {"id":26,"q":"Para protegerte de objetos que caen (struck-by) debes:","opts":["Pararte justo debajo de cargas suspendidas","Quitarte el casco por comodidad","Apilar materiales sueltos en los bordes","Usar casco y colocar rodapiés o mallas"],"re":"Los cascos, rodapiés, mallas y barricadas protegen de los objetos que caen."},
  {"id":27,"q":"Una zanja necesita un sistema de protección (talud, entibado o caja) cuando tiene al menos:","opts":["2 pies de profundidad","5 pies de profundidad","20 pies de profundidad","Solo después de derrumbarse"],"re":"Las zanjas de 5 pies o más necesitan un sistema de protección, salvo que estén cortadas totalmente en roca estable."},
  {"id":28,"q":"El material excavado (spoil) debe mantenerse alejado del borde de la zanja al menos:","opts":["2 pies","6 pulgadas","Puede estar en el borde","10 pies en todos los casos"],"re":"Mantén el material y el equipo al menos a 2 pies del borde para reducir la carga de derrumbe y la caída de material."},
  {"id":29,"q":"En una zanja de 4 pies o más, una escalera o rampa debe estar a no más de:","opts":["25 pies de recorrido lateral","100 pies","Cualquier lugar de la obra","No hay requisito"],"re":"Debe haber una salida a no más de 25 pies de recorrido lateral en zanjas de 4 pies o más."},
  {"id":30,"q":"Una excavación debe inspeccionarse antes de cada turno por:","opts":["Una persona competente","Cualquier recién contratado","Nadie en particular","El repartidor"],"re":"Una persona competente debe inspeccionar la excavación a diario y cuando cambien las condiciones."},
  {"id":31,"q":"Para evitar lesiones por atrapamiento alrededor de maquinaria debes:","opts":["Usar ropa suelta y joyas","Meter la mano en equipo en marcha","Quitar guardas para ir más rápido","Mantener las guardas puestas y alejarte de los puntos de pellizco"],"re":"Mantén las guardas puestas, asegura la ropa suelta y evita los puntos de pellizco y rotación."},
  {"id":32,"q":"El lugar más peligroso cerca de maquinaria móvil es:","opts":["Lejos de la máquina","Dentro de la cabina","En los puntos ciegos y el radio de giro del operador","En la caja de herramientas"],"re":"Mantente fuera de los puntos ciegos y del radio de giro, y haz contacto visual con el operador."},
  {"id":33,"q":"Las partículas que vuelan al esmerilar o picar se controlan mejor con:","opts":["Ojos descubiertos","Lentes de sol tintados","Lentes de seguridad o careta","Nada"],"re":"Usa lentes de seguridad o careta con clasificación de impacto al esmerilar, cortar o picar."},
  {"id":34,"q":"Los cilindros de gas comprimido deben:","opts":["Acostarse de lado, sin tapa","Dejarse caer para rodarlos","Guardarse junto a una fuente de calor","Asegurarse de pie con la tapa de válvula puesta cuando no se usan"],"re":"Asegura los cilindros de pie, coloca la tapa de válvula cuando no se usen y separa el combustible del oxígeno."},
  {"id":35,"q":"PPE significa:","opts":["Equipo de Protección Personal","Cercado de Propiedad Pública","Ingeniería de Procesos de Planta","Evaluación de Desempeño Personal"],"re":"PPE significa Equipo de Protección Personal — protección de cabeza, ojos, manos, pies, oídos y respiratoria."},
  {"id":36,"q":"Un programa de conservación auditiva suele exigirse con un promedio de ruido de 8 horas de:","opts":["55 dBA","70 dBA","85 dBA","120 dBA"],"re":"Se exige un programa de conservación auditiva con un promedio ponderado de 8 horas de 85 dBA."},
  {"id":37,"q":"Antes de usar un respirador ajustado, el trabajador debe tener:","opts":["Nada en especial","Solo barba","Solo una renuncia firmada","Una evaluación médica y una prueba de ajuste"],"re":"Los respiradores ajustados requieren una evaluación médica y una prueba de ajuste antes de usarse."},
  {"id":38,"q":"La Norma de Comunicación de Peligros también se conoce como:","opts":["La Regla del Silencio","Derecho a Saber (Right-to-Know)","Pagar para Jugar","La Regla de Caídas"],"re":"HazCom es la norma de Derecho a Saber, que informa a los trabajadores sobre los peligros químicos."},
  {"id":39,"q":"La información detallada de peligros y manejo de un químico está en su:","opts":["Hoja de Datos de Seguridad (SDS)","Tarjeta de tiempo","Recibo de pago","Plano"],"re":"La Hoja de Datos de Seguridad (SDS), con 16 secciones estándar, detalla los peligros y el manejo seguro del químico."},
  {"id":40,"q":"Bajo el GHS, la etiqueta de un envase químico debe incluir:","opts":["Solo un precio","Solo un código de color","Un identificador del producto, palabra de advertencia, pictograma(s) y declaraciones de peligro","Nada en particular"],"re":"Las etiquetas GHS llevan el identificador del producto, la palabra de advertencia, pictogramas y declaraciones de peligro y precaución."},
  {"id":41,"q":"El pictograma GHS de calavera y huesos cruzados advierte que un químico es:","opts":["Inofensivo","Comestible","Frío al tacto","Tóxico agudo (puede causar muerte o daño grave)"],"re":"El pictograma de calavera y huesos cruzados advierte de toxicidad aguda."},
  {"id":42,"q":"Las dos palabras de advertencia del GHS son:","opts":["Pare y Siga","Peligro y Advertencia","Caliente y Frío","Alto y Bajo"],"re":"El GHS usa Peligro para riesgos más graves y Advertencia para los menos graves."},
  {"id":43,"q":"El método PASS describe cómo:","opts":["Subir una escalera","Operar un extintor (Pull, Aim, Squeeze, Sweep — jalar, apuntar, apretar, barrer)","Levantar una carga pesada","Probar el aire"],"re":"PASS — jala el seguro, apunta a la base, aprieta la manija y barre de lado a lado."},
  {"id":44,"q":"Un extintor Clase C es para incendios de:","opts":["Madera y papel","Líquidos inflamables","Equipo eléctrico energizado","Aceite de cocina"],"re":"La Clase C es para equipo eléctrico energizado; la Clase A es combustibles ordinarios y la Clase B líquidos inflamables."},
  {"id":45,"q":"El buen orden y limpieza en la obra ayuda principalmente a prevenir:","opts":["Descansos más largos","Mejor paga","Internet más rápido","Resbalones, tropiezos y peligros de incendio"],"re":"Mantener los pasillos despejados y los residuos controlados previene resbalones, tropiezos, caídas e incendios."},
  {"id":46,"q":"Antes de usar una herramienta eléctrica debes:","opts":["Quitarle la guarda","Inspeccionarla y mantener las guardas puestas","Cargarla por el cable","Usarla bajo la lluvia"],"re":"Inspecciona las herramientas, mantén las guardas puestas y nunca cargues ni desconectes una herramienta por el cable."},
  {"id":47,"q":"Para prevenir enfermedades por calor, el empleador debe proporcionar:","opts":["Agua, descanso y sombra","Solo café extra","Ropa más gruesa","Menos pausas para tomar agua"],"re":"Agua, descanso y sombra son las defensas básicas contra las enfermedades por calor."},
  {"id":48,"q":"Un espacio confinado que requiere permiso debe:","opts":["Entrarse de inmediato","Dejarse abierto para ventilar","Usarse para almacenamiento","Probarse la atmósfera y entrarse solo con los procedimientos adecuados"],"re":"Los espacios confinados con permiso requieren prueba de atmósfera, un asistente y procedimientos de entrada."},
  {"id":49,"q":"La forma correcta de levantar un objeto pesado es:","opts":["Doblar la cintura y girar","Levantar con las piernas, mantener la carga cerca y evitar girar","Sostenerlo lejos del cuerpo","Levantarlo lo más rápido posible"],"re":"Levanta con las piernas, mantén la carga cerca y no gires; pide ayuda o usa un dispositivo para cargas pesadas."},
  {"id":50,"q":"Si encuentras una condición insegura que no puedes corregir, debes:","opts":["Reportarla a tu supervisor o a la persona competente","Ignorarla","Ocultarla a los demás","Abandonar la obra"],"re":"Reporta los peligros que no puedas corregir a un supervisor o persona competente para que se solucionen."}
];
